await foreach (StreamingResponseUpdate responseUpdate in responseUpdates)
{
    if (responseUpdate is StreamingResponseOutputTextDeltaUpdate outputTextDeltaUpdate)
    {
        Console.Write(outputTextDeltaUpdate.Delta);
    }
}

